-        (plant.get('growthSpeedMultiplier', 1) is number) &&
-        (plant.get('yieldMultiplier', 1) is number) &&
-        (!('color' in plant) || plant.color is string)
-      );
-    }
-
-    function isValidOrchard(orchard) {
-      return orchard.id is string && orchard.id.size() < 50 &&
-             orchard.name is string && orchard.name.size() < 100 &&
