-             (orchard.get('unlockCost', 0) is number);
-    }
-
-    function isValidUser(data) {
-      return (data.get('uid', request.auth.uid) == request.auth.uid) &&
-             (data.get('credits', 0) is number) &&
-             (data.get('dataSeeds', 0) is number) &&
