-             data.amount is number && data.amount > 0 &&
-             data.timestamp == request.time;
-    }
-
-    // ===============================================================
-    // Rules
-    // ===============================================================
-
-    match /users/{userId} {
-      // Users can only read their own profile
-      allow read: if isOwner(userId) || isAdmin();
