-                     request.query.filters[0].op == '==' && 
-                     request.query.filters[0].path == 'uid') ||
-                    (request.query.limit <= 10 && 
-                     (request.query.orders[0].path == 'credits' || request.query.orders[0].path == 'dataSeeds'))
-                  );
-
-      allow create: if isOwner(userId) && 
-                      isValidUser(request.resource.data) &&
-                      (request.resource.data.get('role', 'player') == 'player');
-
-      allow update: if isAuthenticated() && (
-                      (isOwner(userId) && 
-                       uidUnchanged() &&
-                       isValidUser(request.resource.data) &&
-                       request.resource.data.get('role', resource.data.get('role', 'player')) == resource.data.get('role', 'player')) || 
-                      (!isOwner(userId) && 
-                       request.resource.data.diff(resource.data).affectedKeys().hasOnly(['credits']) &&
-                       request.resource.data.credits > resource.data.credits &&
-                       (request.resource.data.credits - resource.data.credits) == 
-                       (get(/databases/$(database)/documents/users/$(request.auth.uid)).data.credits - 
-                        getAfter(/databases/$(database)/documents/users/$(request.auth.uid)).data.credits)
-                      ) ||
-                      isAdmin()
-                    );
-    }
-
-    match /transfers/{transferId} {
-      // Only admins or involved parties can read transfers
-      allow read: if isAuthenticated() && (
-        request.auth.uid == resource.data.from || 
-        request.auth.uid == resource.data.to || 
-        isAdmin()
-      );
-
-      // Only authenticated users can create transfers, and they must be the sender
-      allow create: if isAuthenticated() && isValidTransfer(request.resource.data);
-      
-      // Transfers are immutable
-      allow update, delete: if false;
-    }
-
-    // Default deny
-    match /{path=**} {
-      allow read, write: if false;
-    }
-  }
-}
