+    body { font-family: Inter, system-ui, sans-serif; background:#08090a; color:#d1d5db; margin:0; }
+    .wrap { max-width: 860px; margin: 0 auto; padding: 48px 20px; }
+    a { color: #14b8a6; text-decoration: none; }
+    .card { display:block; border:1px solid #1f2937; background:#111827; border-radius:12px; padding:20px; margin-bottom:16px; }
+    .tags { display:flex; flex-wrap:wrap; gap:8px; margin-top:12px; }
+    .pill { border:1px solid #1f2937; border-radius:999px; padding:2px 8px; font-size:12px; }
+  </style>
+</head>
+<body>
+  <div class="wrap">
+    <h1>Zayvora</h1>
+    <p>Articles tagged with <code>zayvora</code>, <code>local-research</code>, or <code>knowledge-systems</code>.</p>
+    <div id="list"></div>
+  </div>
+  <script>
+    (async function () {
+      const targetTags = ['zayvora', 'local-research', 'knowledge-systems'];
+      const list = document.getElementById('list');
+      const res = await fetch('../data/articles.json', { cache: 'no-store' });
+      const rows = await res.json();
+      const matches = rows.filter((article) => (article.tags || []).some((tag) => targetTags.includes(String(tag).toLowerCase())));
+      list.innerHTML = matches.map((article) => `
+        <a class="card" href="../${article.path.replace(/^\//, '')}">
+          <small>${article.date || ''}</small>
+          <h2>${article.title}</h2>
+          <p>${article.description || ''}</p>
+          <div class="tags">${(article.tags || []).map((tag) => `<span class="pill">${tag}</span>`).join('')}</div>
+        </a>
+      `).join('') || '<p>No Zayvora articles yet.</p>';
+    })();
+  </script>
+</body>
+</html>
